What is the output of the following code snippet?

```c
#include <stdio.h>
struct Data {
    int a;
    char b;
    float c;
};
int main() {
    struct Data d = {.b='Z', .a=10};
    printf("%d, %c, %.1f", d.a, d.b, d.c);
    return 0;
}
```

